diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index 76234ccfdcff..fe0caf685e8c 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -2029,8 +2029,67 @@ Instruction *InstCombinerImpl::visitSub(BinaryOperator &I) {
     // C-(C2-X) --> X+(C-C2)
     if (match(Op1, m_Sub(m_ImmConstant(C2), m_Value(X))))
       return BinaryOperator::CreateAdd(X, ConstantExpr::getSub(C, C2));
+    // C1 - ((C2 - X) & mask) --> (X & mask) + (C1 - (C2 & mask))
+    // when ~mask + 1 is a power of 2, or when the inner sub has nuw and (C2 & ~mask + 1) is a power of 2
+    // and (mask | C2) + 1 is a power of 2.
+    Value *X2;
+    Constant *C2_2, *MaskC;
+    if (match(Op1, m_And(m_OneUse(m_Sub(m_ImmConstant(C2_2), m_Value(X2))),
+                         m_Constant(MaskC)))) {
+      // Check if the inner sub has nuw flag.
+      BinaryOperator *SubInst = nullptr;
+      if (auto *AndInst = dyn_cast<BinaryOperator>(Op1)) {
+        if (auto *BO = dyn_cast<BinaryOperator>(AndInst->getOperand(0)))
+          if (BO->getOpcode() == Instruction::Sub) SubInst = BO;
+        if (!SubInst)
+          if (auto *BO = dyn_cast<BinaryOperator>(AndInst->getOperand(1)))
+            if (BO->getOpcode() == Instruction::Sub) SubInst = BO;
+      }
+      bool HasNuw = SubInst && SubInst->hasNoUnsignedWrap();
+      
+      // Get scalar values from constants (handles both scalar and splat vectors).
+      ConstantInt *C1Scalar, *C2Scalar, *MaskScalar;
+      if (C->getType()->isVectorTy()) {
+        Constant *C1Splat = C->getSplatValue();
+        Constant *C2Splat = C2_2->getSplatValue();
+        Constant *MaskSplat = MaskC->getSplatValue();
+        if (!C1Splat || !C2Splat || !MaskSplat) return nullptr;
+        C1Scalar = dyn_cast<ConstantInt>(C1Splat);
+        C2Scalar = dyn_cast<ConstantInt>(C2Splat);
+        MaskScalar = dyn_cast<ConstantInt>(MaskSplat);
+      } else {
+        C1Scalar = dyn_cast<ConstantInt>(C);
+        C2Scalar = dyn_cast<ConstantInt>(C2_2);
+        MaskScalar = dyn_cast<ConstantInt>(MaskC);
+      }
+      if (!C1Scalar || !C2Scalar || !MaskScalar) return nullptr;
+      
+      APInt C1Val = C1Scalar->getValue();
+      APInt C2Val = C2Scalar->getValue();
+      APInt MaskVal = MaskScalar->getValue();
+      bool Cond1 = (~MaskVal + 1).isPowerOf2();
+      APInt C2AndNotMask = C2Val & ~MaskVal;
+      APInt MaskOrC2 = MaskVal | C2Val;
+      bool Cond2 = HasNuw && (C2AndNotMask + 1).isPowerOf2() && (MaskOrC2 + 1).isPowerOf2();
+      if (Cond1 || Cond2) {
+        APInt ResultMask = MaskVal;
+        APInt AddConst = C1Val - (C2Val & MaskVal);
+        Constant *ResultMaskConst = C->getType()->isVectorTy()
+          ? ConstantVector::getSplat(cast<VectorType>(C->getType())->getElementCount(),
+                                     ConstantInt::get(C1Scalar->getType(), ResultMask))
+          : ConstantInt::get(C->getType(), ResultMask);
+        if (AddConst.isZero()) {
+          return BinaryOperator::CreateAnd(X2, ResultMaskConst);
+        }
+        Constant *AddConstConst = C->getType()->isVectorTy()
+          ? ConstantVector::getSplat(cast<VectorType>(C->getType())->getElementCount(),
+                                     ConstantInt::get(C1Scalar->getType(), AddConst))
+          : ConstantInt::get(C->getType(), AddConst);
+        Value *And = Builder.CreateAnd(X2, ResultMaskConst);
+        return BinaryOperator::CreateAdd(And, AddConstConst);
+      }
+    }
   }
-
   const APInt *Op0C;
   if (match(Op0, m_APInt(Op0C)) && Op0C->isMask()) {
     // Turn this into a xor if LHS is 2^n-1 and the remaining bits are known

